package com.spsp.debug;
import java.util.Random;
import java.util.Scanner;

public class NumberProcessor {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        Random random = new Random();
        System.out.println("请输入一个整数n：");
        int n = scanner.nextInt();
        try {


        int[] numbers = new int[n];
        //生成一个包含n个随机整数（范围从1到100）的数组。。
        for (int i = 0; i < n; i++) {
            numbers[i] = random.nextInt(100) +1;}

        // 计算平均值
        double sum = 0;
        for (int num : numbers) {
            sum += num;
        }
        double average = sum / n;

        // 找到最大值和最小值
        int max = numbers[0];
        int min = numbers[0];
        for (int num : numbers) {
            if (num > max) {
                max= num;
            }
            if (num < min) {
                min= num;
            }
        }


        // 对数组进行排序
        for (int i = 0; i < numbers.length - 1; i++) {
            for (int j = 0; j < numbers.length - i - 1; j++) {
                if (numbers[j] > numbers[j + 1]) {
                    int temp = numbers[j];
                    numbers[j] = numbers[j + 1];
                    numbers[j + 1] = temp;
                }
            }
        }

        // 输出结果
        System.out.println("生成的数组：" + java.util.Arrays.toString(numbers));
        System.out.println("平均值：" + average);
        System.out.println("最大值：" + max);
        System.out.println("最小值：" + min);
        System.out.println("排序后的数组：" + java.util.Arrays.toString(numbers));


    }catch (Exception e){
  System.out.println("输入错误，请输入一个整数！");
        }finally {
            scanner.close();
        }
}}

package com.spsp.debug;

import java.util.HashMap;
import java.util.Map;
import java.util.Scanner;

public class StringProcessor {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.println("请输入一个字符串：");
        String input = scanner.nextLine();

        // 1. 检查输入是否为空
         if(input.isEmpty()){
             System.out.println("输入错误，请输入一个非空字符串！");
         }
        // 2. 计算并输出字符串的长度
        int length = input.length();
        System.out.println("字符串的长度是：" + length);

        // 3. 统计并输出字符串中每个字符出现的次数
        Map<Character, Integer> charCount = new HashMap<>();
        for (char c : input.toCharArray()) {

            if (charCount.containsKey(c)) {
                charCount.put(c, charCount.get(c) + 1);
            }else{
                charCount.put(c, 1);
            }
        }
        System.out.println("字符出现次数：" + charCount);

        // 4. 将字符字母顺序排序，并输出排序后的字符
        char[] chars = input.toCharArray();
        for(int i=0;i<chars.length;i++){
            for(int j= i+1;j<=chars.length-1;j++){
                if(chars[i]>chars[j]){
                    char temp = chars[i];
                    chars[i]= chars[j];
                    chars[j]=temp;
                }
            }
        }
        String sortedString = new String(chars);
        System.out.println("排序后的字符串：" + sortedString);
    }
}

package com.spsp.debug;

import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.util.Arrays;
import java.util.HashMap;
import java.util.Map;

public class FileProcessor {

    public static void main(String[] args) {
        BufferedReader reader = null;
        StringBuilder sb = null;

        try {
            reader = new BufferedReader(new InputStreamReader(FileProcessor.class.getClassLoader().getResource("com/spsp/debug/input.txt").openStream()));
            sb = new StringBuilder();
            String line;
            while ((line = reader.readLine()) != null) {
                sb.append(line);
            }
            reader.close();
        }catch (IOException e){
            throw new RuntimeException(e);
        }

        // 1. 计算并输出文本的字符总数
        int charCount = sb.length();
        System.out.println("文本的字符总数是：" + charCount);

        //2.统计每个单词出现的次数
        Map<String, Integer> wordCountMap = new HashMap<>();
        String[] words = sb.toString().split("\\s+");
        for (String word : words) {

            if (wordCountMap.containsKey(word)) {
                wordCountMap.put(word, wordCountMap.get(word) + 1);
            }else{
                wordCountMap.put(word, 1);
            }
        }
        System.out.println("单词出现次数：" + wordCountMap);

        //3.对单词进行按字母顺序排序
        for (int i = 0; i < words.length; i++) {
            for (int j = 0; j < words.length -i- 1; j++) {
                if (words[j].compareTo(words[j + 1]) > 0) {
                    String temp = words[j];
                    words[j] = words[j + 1];
                    words[j + 1] = temp;
                }
            }
        }
        System.out.println("排序后的文本：" + Arrays.toString(words));
    }
}

package com.spsp.debug;

import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.util.HashMap;
import java.util.Map;

public class TextAnalyzer {

    public static void main(String[] args) throws Exception {
            BufferedReader reader = new BufferedReader(new InputStreamReader(TextAnalyzer.class.getClassLoader().getResource("com/spsp/debug/input.txt").openStream()));
            StringBuilder content = new StringBuilder();
            String line;
            //1.一行行读取文本内容赋值到StringBuilder变量中
            while ((line = reader.readLine()) != null) {
                content.append(line).append("\n");
            }
            reader.close();

            String text = content.toString();

            // 2. 计算并输出文本中元音字母出现的总次数
            int vowelCount = 0;
            for (char c : text.toCharArray()) {
                if ("aeiou".indexOf(Character.toLowerCase(c)) != -1) {
                    vowelCount++;
                }
            }
            System.out.println("元音字母总次数：" + vowelCount);

            // 3 找出并输出出现频率最高的单词
            String[] words = text.split("\\s+");
            Map<String, Integer> wordCount = new HashMap<>();
            for (String word : words) {

                if(wordCount.containsKey(word)){
                    wordCount.put(word, wordCount.get(word) + 1);
                }else {
                    wordCount.put(word,1);
                }

            }
            String mostFrequentWord = null;
            int maxCount = 0;
            for (Map.Entry<String, Integer> entry : wordCount.entrySet()) {
                if (entry.getValue() > maxCount) {
                    mostFrequentWord = entry.getKey();
                    maxCount = entry.getValue();
                }
            }
            System.out.println("最频繁的单词：" + mostFrequentWord);

            // 4. 找出并输出长度最长的单词
            String longestWord = "";
            for (String word : words) {
                if (word.length() > longestWord.length()) {
                    longestWord = word;
                }
            }
            System.out.println("最长的单词：" + longestWord);

            // 5. 统计并输出每个句子的单词数量
            String[] sentences = text.split("[.!?]");
            for (String sentence : sentences) {
                if(sentence.trim().isEmpty())continue;
                int wordCountInSentence = sentence.split("\\s+").length;
                System.out.println("句子的单词数量：" + wordCountInSentence);
            }

    }
}

package com.spsp.debug;

import java.io.*;
import java.util.*;

public class DataAnalyzer {
    public static void main(String[] args) {
        List<Integer> data = loadData("data.txt");
        //1.数据有效性检查
        if(data.isEmpty()||data==null){
            System.out.println("“No data to analyze.");
        }
        System.out.println("Average: " + calculateAverage(data));
        System.out.println("Max: " + findMax(data));
        System.out.println("Min: " + findMin(data));
        countOccurrences(data);
    }

    //读取文本内的内容并转换成数值
    public static List<Integer> loadData(String filename) {
        List<Integer> data = new ArrayList<>();
        try (BufferedReader br = new BufferedReader(new InputStreamReader(DataAnalyzer.class.getClassLoader().getResource(filename).openStream()))) {
            String line;
            while ((line = br.readLine()) != null) {
                data.add(Integer.parseInt(line));
            }
        }catch (NumberFormatException e){
            System.out.println("数值转换异常！");
        }
        catch (IOException e) {
            e.printStackTrace();
        }
        return data;
    }

    //计算平均分
    public static double calculateAverage(List<Integer> data) {
        int sum = 0;
        for (int num : data) {
            sum += num;
        }
        return (double)sum / data.size();
    }

    //求最大值
    public static int findMax(List<Integer> data) {
        int max = Integer.MIN_VALUE;
        for (int num : data) {
            if (num > max) {
                max = num;
            }
        }
        return max;
    }

    //求最小值
    public static int findMin(List<Integer> data) {
        int min = Integer.MAX_VALUE;
        for (int num : data) {
            if (num < min) {
                min = num;
            }
        }
        return min;
    }

    //统计数字出现的次数
    public static void countOccurrences(List<Integer> data) {
        Map<Integer, Integer> occurrences = new HashMap<>();
        for (int num : data) {
            occurrences.put(num, occurrences.getOrDefault(num, 0) + 1);
        }
        for (Map.Entry<Integer, Integer> entry : occurrences.entrySet()) {
            System.out.println(entry.getKey() + ": " + entry.getValue());
        }
    }
}
